mapper.update:
UPDATE t_risk_exposure
SET total_long_qty = total_long_qty - #{quantity},
    net_exposure = total_long_qty - total_short_qty,
    net_exposure_usd = (total_long_qty - total_short_qty) * #{markPrice},
    updated_at = #{updatedAt}
WHERE symbol = #{symbol}
  AND total_long_qty >= #{quantity}

UPDATE t_risk_exposure
SET total_short_qty = total_short_qty - #{quantity},
    net_exposure = total_long_qty - total_short_qty,
    net_exposure_usd = (total_long_qty - total_short_qty) * #{markPrice},
    updated_at = #{updatedAt}
WHERE symbol = #{symbol}
  AND total_short_qty >= #{quantity}

UPDATE t_risk_exposure
SET net_exposure_usd = CASE
                           WHEN net_exposure < 0 THEN net_exposure * #{askPrice}
                           ELSE net_exposure * #{bidPrice}
    END,
    updated_at = #{updatedAt}
WHERE symbol = #{symbol}
